// app/components/Author/Author.tsx
import Image from "next/image";
import Link from "next/link";
import { AuthorData, AuthorProps } from "@/types/components/author";

export function Author({
  author,
  showAvatar = true,
  showCredentials = true,
  showCountry = true,
  showBio = false,
  showEmail = false,
  showLinkedIn = false,
  showSpecialties = true,
  className = "",
}: AuthorProps) {
  // Helper function to strip HTML tags
  const stripHtml = (html: string): string => {
    return html.replace(/<[^>]*>/g, "").trim();
  };

  // Get author name from either field
  const authorName = stripHtml(author.author_name || author.name || "");

  // Get avatar from either field and strip HTML
  const authorImage = stripHtml(author.avatar || author.image || "");

  // Get other fields and strip HTML
  const credentials = author.credentials ? stripHtml(author.credentials) : "";
  const country = author.author_country ? stripHtml(author.author_country) : "";
  const field = author.specialties?.[0] ? stripHtml(author.specialties[0]) : "";

  // Generate URL-encoded author name for tag search
  const encodedAuthorName = encodeURIComponent(authorName || "");

  // Return null if no author information
  if (!authorName) return null;

  return (
    <Link
      href={`/tag/${encodedAuthorName}`}
      className="block hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg px-4 py-1 transition-colors duration-200 cursor-pointer"
    >
      <div className={`author-component ${className}`}>
        <table className="w-full">
          <tbody>
            <tr>
              <td className="w-20 pr-4 align-middle">
                {showAvatar && authorImage && (
                  <div className="author-avatar">
                    <Image
                      src={authorImage}
                      alt={authorName || "Author"}
                      width={60}
                      height={60}
                      className="rounded-full"
                    />
                  </div>
                )}
              </td>
              <td className="align-top">
                <div className="author-info">
                  {authorName && (
                    <div className="author-name font-medium text-gray-900 dark:text-white block">
                      {authorName}
                      {showCredentials && credentials && (
                        <span className="ml-1 author-credentials font-medium text-gray-600 dark:text-gray-400">
                          {credentials}
                        </span>
                      )}
                    </div>
                  )}

                  {showSpecialties && field && (
                    <div className="author-field text-md text-gray-600 dark:text-gray-400">
                      {field}
                    </div>
                  )}

                  {showCountry && country && (
                    <div className="author-country text-sm text-gray-500 dark:text-gray-500">
                      {country}
                    </div>
                  )}
                </div>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </Link>
  );
}

// app/components/BadgeSymbol/BadgeSymbol.tsx
"use client";

import React from "react";
import "./styles.css"; // Import the styles
import { BadgeSymbolData, BadgeVariant } from "@/types/core";

interface BadgeSymbolProps {
  content: string;
  config?: BadgeSymbolData & {
    variant?: BadgeVariant;
    className?: string;
  };
}

export function BadgeSymbol({ content, config }: BadgeSymbolProps) {
  if (!config) return null;

  const { 
    symbol, 
    materialType, 
    atomicNumber, 
    formula, 
    variant = "card", 
    className = "" 
  } = config;

  // If no symbol is provided, don't render
  if (!symbol) {
    return null;
  }

  // Format symbol with proper case and limit to 3 characters following chemical symbol conventions
  function formatSymbol(input?: string): string {
    if (!input) return "";

    // Limit to 3 characters
    const limitedSymbol = input.substring(0, 3);

    // Handle chemical symbol conventions:
    // - Single-letter symbols are uppercase (H, C, O)
    // - Multi-letter symbols have first letter uppercase, rest lowercase (He, Al, Si, Fe)
    // - Two-letter standard element symbols never have both letters uppercase
    if (limitedSymbol.length === 1) {
      return limitedSymbol.toUpperCase();
    } else {
      // For two or more letters, capitalize first letter only
      return (
        limitedSymbol.charAt(0).toUpperCase() +
        limitedSymbol.slice(1).toLowerCase()
      );
    }
  }

  // Format the symbol for display
  const displaySymbol = formatSymbol(symbol);

  // Determine if we have a complex formula that needs special handling
  const isComplexFormula =
    displaySymbol.length > 2 || /[0-9]/.test(displaySymbol);

  // Configure sizes based on variant and complexity
  const sizeConfig = {
    card: {
      container: isComplexFormula ? "w-12 h-12" : "w-8 h-8",
      symbol: isComplexFormula ? "text-lg" : "text-md",
      number: "text-xs"
    },
    large: {
      container: isComplexFormula ? "w-16 h-16" : "w-14 h-14",
      symbol: isComplexFormula ? "text-xl" : "text-2xl",
      number: "text-sm"
    },
    small: {
      container: isComplexFormula ? "w-8 h-8" : "w-7 h-7",
      symbol: isComplexFormula ? "text-sm" : "text-base",
      number: "text-[8px]"
    },
    inline: {
      container: isComplexFormula ? "w-6 h-6" : "w-5 h-5",
      symbol: isComplexFormula ? "text-xs" : "text-sm",
      number: "text-[6px]"
    }
  };

  // Default text colors - consistent styling
  const textColorConfig = {
    default: "text-gray-100 font-semibold", // Light text for red background
    number: "text-gray-200 font-bold"
  };

  // Utility function to format chemical formula with subscripts
  const formatChemicalFormula = (formula: string): string => {
    return formula.replace(/([0-9]+)/g, "<sub>$1</sub>");
  };

  const sizes = sizeConfig[variant];

  // Build className parts separately for better maintainability
  const containerClasses = [
    sizes.container,
    "bg-red-900", // Red background for visibility
    "rounded-md border border-red-800",
    "flex flex-col items-center justify-center",
    "shadow-sm",
    "badge-container", // Add our custom class for z-index
    className
  ].join(" ");

  return (
    <div className={`badge-symbol ${containerClasses}`}>
      {/* Atomic number if available */}
      {atomicNumber && (
        <span className={`${sizes.number} ${textColorConfig.number} badge-content`}>
          {atomicNumber}
        </span>
      )}

      {/* Symbol or Formula - Use subscripts for numbers in formulas */}
      <span
        className={`${sizes.symbol} ${textColorConfig.default} leading-tight badge-content`}
      >
        {isComplexFormula ? (
          <span
            dangerouslySetInnerHTML={{
              __html: formatChemicalFormula(displaySymbol),
            }}
          />
        ) : (
          displaySymbol
        )}
      </span>

      {/* Debug info - will be hidden in production */}
      {process.env.NODE_ENV === 'development' && (
        <span className="hidden">{`Symbol: ${symbol}, Formula: ${formula}`}</span>
      )}
    </div>
  );
}

// app/components/List/List.tsx
import "./styles.scss";
import React from "react";
import { Card } from "../Card/Card";
import { /* cn */ } from "@/app/utils/helpers";
import { getArticle, loadComponent } from "@/app/utils/contentAPI"; // Updated to use contentAPI
import { MaterialType } from "@/types/core";

// Helper function to safely cast material types
function toMaterialType(value?: string): MaterialType {
  if (!value) return 'other';

  const normalizedValue = value.toLowerCase();
  const validTypes: MaterialType[] = [
    'element', 'compound', 'ceramic', 'polymer', 'alloy', 'composite', 'semiconductor', 'other'
  ];

  // Check for exact matches first
  if (validTypes.includes(normalizedValue as MaterialType)) {
    return normalizedValue as MaterialType;
  }

  // Map common aliases
  const typeMap: Record<string, MaterialType> = {
    'metal': 'alloy',
    'metalloid': 'semiconductor',
    'plastic': 'polymer',
    'material': 'other'
  };

  return typeMap[normalizedValue] || 'other';
}

interface ListProps {
  // Add slugs as a prop alternative to items
  slugs?: string[];
  items?: Array<{
    slug: string;
    title?: string;
    description?: string;
    image?: string;
    badge?: string;
    featured?: boolean; // Add featured property
  }>;
  title?: string;
  heading?: string; // Add heading as an alias for title
  columns?: 1 | 2 | 3 | 4;
  filterBy?: string;
  className?: string;
}

// Update your existing ArticleMetadata interface at the top of the file
interface ArticleMetadata {
  subject?: string;
  description?: string;
  category?: string;
  articleType?: string;
  image?: string;
  chemicalSymbol?: string;
  atomicNumber?: number;
  chemicalFormula?: string;
  // Add the properties field
  properties?: {
    chemicalFormula?: string;
    density?: string;
    meltingPoint?: string;
    thermalConductivity?: string;
    laserType?: string;
    wavelength?: string;
    fluenceRange?: string;
  };
  // Add composition field
  composition?: Array<{
    component: string;
    percentage: string;
    type: string;
    formula?: string;
  }>;
  // Optional: Add this for flexibility with other fields
  [key: string]: unknown;
}

interface Article {
  metadata: ArticleMetadata;
  components: Record<string, unknown> | null;
}

export async function List({
  slugs,
  items,
  title,
  heading,
  columns = 3,
  filterBy = "all",
  className = "",
}: ListProps) {
  // Use heading for title
  const displayTitle = title || heading;

  // Process items from either slugs or items prop
  const processedItems = items || [];

  // If slugs are provided but not items, create items from slugs
  if (slugs && !items) {
    const slugItems = slugs.map((slug) => ({ slug }));
    processedItems.push(...slugItems);
  }

  // Fetch articles - Update the return object structure
  const articles = await Promise.all(
    processedItems.map(async (item) => {
      const article = (await getArticle(item.slug)) as Article | null;

      // Create badge object with proper structure
      const badgeText = item.badge || article?.metadata?.category;
      const badgeObject = badgeText
        ? {
            text: badgeText,
            color: getCategoryColor(article?.metadata?.category),
          }
        : undefined;

      // Determine image with fallbacks
      const imageUrl = getArticleImage(item, article);

      // Extract chemical data from article
      let chemicalSymbol = article?.metadata?.chemicalSymbol;
      const atomicNumber = article?.metadata?.atomicNumber;
      let chemicalFormula = article?.metadata?.chemicalFormula;

      // If not directly in metadata, try to get from properties
      if (!chemicalFormula && article?.metadata?.properties?.chemicalFormula) {
        chemicalFormula = article.metadata.properties.chemicalFormula;
      }

      // If we have a formula but no symbol, extract symbol from formula or name
      if (chemicalFormula && !chemicalSymbol) {
        // Extract first element from formula (e.g., "Al" from "Al₂O₃")
        const match = chemicalFormula.match(/([A-Z][a-z]?)/);
        chemicalSymbol = match
          ? match[0]
          : article?.metadata?.subject?.substring(0, 2) || "";
      }

      // Load BadgeSymbol data from content/components/badgesymbol/
      let badgeSymbolData: {
        symbol: string;
        materialType?: MaterialType;
        atomicNumber?: number;
        formula?: string;
      } | null = null;
      try {
        const badgeSymbol = await loadComponent('badgesymbol', item.slug);
        if (badgeSymbol?.config) {
          const config = badgeSymbol.config as Record<string, unknown>; // More specific type
          const symbolValue = config.symbol || chemicalSymbol;
          if (symbolValue) {
            badgeSymbolData = {
              symbol: String(symbolValue),
              materialType: config.materialType ? toMaterialType(String(config.materialType)) : toMaterialType(article?.metadata?.category as string),
              atomicNumber: config.atomicNumber ? Number(config.atomicNumber) : atomicNumber,
              formula: config.formula ? String(config.formula) : chemicalFormula,
            };
          }
        }
      } catch (error) {
        // If no BadgeSymbol content file exists, fall back to article metadata
        if (chemicalSymbol) {
          badgeSymbolData = {
            symbol: chemicalSymbol,
            materialType: toMaterialType(article?.metadata?.category as string),
            atomicNumber: atomicNumber,
            formula: chemicalFormula,
          };
        }
      }

      return {
        slug: item.slug,
        title: article?.metadata?.subject || item.title || item.slug,
        description: article?.metadata?.description || item.description || "",
        badge: badgeObject,
        imageUrl: imageUrl,
        category: article?.metadata?.category || "",
        articleType: article?.metadata?.articleType || "",
        // Add these properties directly to the item
        chemicalSymbol,
        atomicNumber,
        chemicalFormula,
        // Pass the featured flag
        featured: item.featured,
        // Pass the full article for other needs
        materialData: article,
        // Pass the loaded BadgeSymbol data
        badgeSymbolData,
      };
    })
  );

  // Filter articles
  const filteredItems =
    filterBy === "all"
      ? articles
      : articles.filter((a) => a.articleType === filterBy);

  const gridCols = {
    1: "grid-cols-1",
    2: "grid-cols-2 md:grid-cols-2",
    3: "grid-cols-2 md:grid-cols-2 lg:grid-cols-3",
    4: "grid-cols-2 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4",
  };

  if (!filteredItems?.length) return null;

  return (
    <div className={`list-section ${className}`}>
      {displayTitle && <h2 className="list-title">{displayTitle}</h2>}

      <div className={`grid gap-4 ${gridCols[columns]}`}>
        {filteredItems.map((item) => {
          // We'll still hide the BadgeSymbol for featured items
          const isFeatured = item.featured;

          return (
            <Card
              key={item.slug}
              title={item.title}
              description={item.description}
              href={`/${item.slug}`}
              badge={item.badgeSymbolData || {
                symbol: item.chemicalSymbol,
                formula: item.chemicalFormula,
                atomicNumber: item.atomicNumber,
                materialType: toMaterialType(item.category),
              }}
              imageUrl={item.imageUrl}
              imageAlt={item.title}
              metadata={item.materialData?.metadata || {
                category: item.category,
                articleType: item.articleType,
              }}
              height={isFeatured ? "auto" : undefined}
            />
          );
        })}
      </div>
    </div>
  );
}

// Helper function to get article image with fallbacks
function getArticleImage(
  item: { slug: string; image?: string },
  article: Article | null
): string | undefined {
  // First, try to use the directly provided image
  if (item.image) return item.image;

  // Then, try to get the image from the article metadata
  const metadataImage = article?.metadata?.image;
  if (metadataImage) return metadataImage;

  // Try to get OpenGraph image from metadata if available
  const ogImage =
    article?.metadata?.["ogImage"] ||
    (article?.metadata as Record<string, unknown>)?.["openGraph"]?.["images"]?.[0]?.["url"];
  if (ogImage) return ogImage;

  // Return undefined to let the Thumbnail component handle all fallbacks
  return undefined;
}

// Helper function to map categories to colors
function getCategoryColor(
  category?: string
): "blue" | "green" | "purple" | "orange" | undefined {
  if (!category) return undefined;

  const categoryColors: Record<string, "blue" | "green" | "purple" | "orange"> =
    {
      material: "blue",
      application: "green",
      technique: "purple",
      industry: "orange",
      // Add more mappings as needed
    };

  return categoryColors[category.toLowerCase()] || "blue"; // Default to blue
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { SearchResultsGrid } from "./SearchResultsGrid";
import { SearchHeader } from "./SearchHeader";
import { SearchResultsCount } from "./SearchResultsCount";
import { EmptySearchResults } from "./EmptySearchResults";
import { SearchResultItem } from "@/types/core";
import { Article, SearchableArticle } from "@/types/core";

interface SearchResultsProps {
  items: SearchableArticle[];
  initialTag?: string;
  placeholder?: string;
  columns?: 1 | 2 | 3 | 4;
  className?: string;
  showTagFilter?: boolean;
}

export function SearchResults({
  items,
  initialTag = "",
  placeholder = "Search materials, articles, and more...",
  columns = 3,
  className = "",
  showTagFilter = true,
}: SearchResultsProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedTag, setSelectedTag] = useState("");

  // Extract all unique tags from the items
  const allTags = useMemo(() => {
    const tagSet = new Set<string>();

    items.forEach(item => {
      if (item.tags && Array.isArray(item.tags)) {
        item.tags.forEach(tag => {
          if (tag) tagSet.add(tag);
        });
      }
    });

    return Array.from(tagSet).sort();
  }, [items]);

  // Set initial tag from prop
  useEffect(() => {
    if (initialTag) {
      // Decode and normalize the initial tag
      const decodedTag = decodeURIComponent(initialTag)
        .replace(/\+/g, ' ')
        .trim();

      // Check if this tag exists in our items
      const tagExists = items.some(item => 
        item.tags && item.tags.some(t => t.toLowerCase() === decodedTag.toLowerCase())
      );

      // Try finding a capitalized version of the tag if it exists in our items
      if (!tagExists && decodedTag) {
        const allItemTags = new Set<string>();
        items.forEach(item => {
          if (item.tags) {
            item.tags.forEach(tag => {
              if (tag) allItemTags.add(tag);
            });
          }
        });

        // Find the tag with the matching lowercase form
        const matchingTag = Array.from(allItemTags).find(
          tag => tag.toLowerCase() === decodedTag.toLowerCase()
        );

        if (matchingTag) {
          setSelectedTag(matchingTag); // Use the version that exists in the items
          return;
        }
      }

      setSelectedTag(decodedTag);
    }
  }, [initialTag, items]);

  // Simple tag matching function
  function itemMatchesTag(item: SearchableArticle, tag: string): boolean {
    if (!tag) return true;
    if (!item.tags || !Array.isArray(item.tags)) return false;

    const tagLower = tag.toLowerCase();

    // Enhanced matching logic for tags
    const hasMatch = item.tags.some((t: string) => {
      if (!t) return false;

      // Direct match (case-insensitive)
      if (t.toLowerCase() === tagLower) return true;

      return false;
    });

    return hasMatch;
  }

  // Count items matching each tag
  const tagItemCounts = useMemo(() => {
    const counts: Record<string, number> = {};

    // Initialize all tags with zero count
    allTags.forEach(tag => {
      counts[tag] = 0;
    });

    // Count items for each tag
    items.forEach(item => {
      allTags.forEach(tag => {
        if (itemMatchesTag(item, tag)) {
          counts[tag] = (counts[tag] || 0) + 1;
        }
      });
    });

    return counts;
  }, [items, allTags]);

  // Filter to only show tags that have at least one matching item
  const filteredTags = useMemo(() => {
    return allTags.filter(tag => tagItemCounts[tag] > 0);
  }, [allTags, tagItemCounts]);

  // Simple search matching function
  function itemMatchesSearch(item: SearchableArticle, query: string): boolean {
    if (!query) return true;

    const queryLower = query.toLowerCase();

    return (
      // Title
      (item.title && item.title.toLowerCase().includes(queryLower)) ||
      // Description
      (item.description && item.description.toLowerCase().includes(queryLower)) ||
      // Frontmatter title
      (item.frontmatter?.title && item.frontmatter.title.toLowerCase().includes(queryLower)) ||
      // Frontmatter description
      (item.frontmatter?.description && item.frontmatter.description.toLowerCase().includes(queryLower)) ||
      // Tags
      (item.tags && item.tags.some(tag => tag.toLowerCase().includes(queryLower)))
    );
  }

  // Filter items based on search query and selected tag
  const filteredItems = useMemo(() => {
    return items.filter(item => 
      itemMatchesSearch(item, searchQuery) && 
      itemMatchesTag(item, selectedTag)
    ).map(item => ({
      id: item.id || item.slug || 'unknown',
      slug: item.slug || 'unknown',
      title: item.title || 'Untitled',
      name: item.name,
      description: item.description,
      type: item.metadata?.category || 'article',
      category: item.metadata?.category,
      articleType: item.metadata?.category || 'article',
      tags: item.tags,
      href: item.href,
      imageAlt: item.imageAlt || item.title || 'Image',
      image: item.image,
      metadata: item.metadata as Record<string, unknown>, // More specific type
      frontmatter: item.frontmatter,
      content: item.content,
      excerpt: item.excerpt
    } as SearchResultItem));
  }, [items, searchQuery, selectedTag]);

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Search header */}
      <SearchHeader
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        tags={filteredTags}
        selectedTag={selectedTag}
        onTagSelect={setSelectedTag}
        placeholder={placeholder}
        showTagFilter={showTagFilter}
        tagItemCounts={tagItemCounts}
      />

      {/* Results count */}
      <SearchResultsCount
        count={filteredItems.length}
        selectedTag={selectedTag || undefined}
        searchQuery={searchQuery || undefined}
      />

      {/* Results grid or empty state */}
      {filteredItems.length > 0 ? (
        <SearchResultsGrid 
          items={filteredItems} 
          columns={columns} 
        />
      ) : (
        <EmptySearchResults />
      )}
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { sectionCards } from "./SectionCards";
import { Card } from "../Card/Card";

interface SectionCardData {
  id: number;
  title?: string;
  slug: string;
  description: string;
  imageUrl: string;
  featured?: boolean; // Add featured property
}

interface SectionCardListProps {
  cards?: SectionCardData[];
  heading?: string;
  className?: string;
  featured?: boolean; // Add a featured prop
}

export function SectionCardList({
  cards,
  heading,
  className = "",
  featured = false,
}: SectionCardListProps) {
  // Fix: Use the correct imported variable name and filter based on featured prop
  const cardsToRender = useMemo(() => {
    const allCards = cards || sectionCards;
    if (featured) {
      // Only show cards marked as featured when featured prop is true
      return allCards.filter((card) => card.featured);
    }
    return allCards;
  }, [cards, featured]);

  if (featured && cardsToRender.length === 0) {
    return null;
  }

  return (
    <section className={`${className}`}>
      <div className="grid grid-cols-2 gap-4">
        {cardsToRender.map((card) => (
          <Card
            key={card.slug || card.id}
            href={`/${card.slug}`}
            imageUrl={card.imageUrl}
            imageAlt={card.title || card.slug || "Image"}
            title={card.title || ""}
            description={card.description || ""}
            className="featured-item"
            badge={{ show: false }}
          />
        ))}
      </div>
    </section>
  );
}

// app/components/Thumbnail/Thumbnail.tsx
"use client";

import Image from "next/image";
import React, { useState, useEffect } from "react";
import { Article } from "@/types/core";
import { Card } from "../Card/Card";
import { logger } from "../../utils/logger";

type ObjectFit = "fill" | "contain" | "cover" | "none" | "scale-down";

interface ThumbnailProps {
  alt: string;
  className?: string;
  priority?: boolean;
  objectFit?: ObjectFit;
  width?: number;
  height?: number;
  slug?: string; // Add slug to fetch data directly
  frontmatter?: {
    images?: {
      hero?: { url: string };
    };
    [key: string]: unknown;
  }; // Specific structure for images
}

export function Thumbnail({
  alt,
  className = "",
  priority = false,
  objectFit = "cover",
  width,
  height,
  slug,
  frontmatter
}: ThumbnailProps) {
  const [imageUrl, setImageUrl] = useState<string>("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // If we already have frontmatter, use it directly
    if (frontmatter?.images?.hero?.url) {
      setImageUrl(frontmatter.images.hero.url);
      return;
    }

    // If we have a slug, fetch the data directly
    if (slug && !frontmatter) {
      setLoading(true);
      fetch(`/api/articles/${slug}`)
        .then(response => response.json())
        .then(data => {
          if (data?.metadata?.images?.hero?.url) {
            setImageUrl(data.metadata.images.hero.url);
          } else {
            setImageUrl("");
          }
        })
        .catch(error => {
          logger.error("Error fetching thumbnail data", error, { slug });
          setImageUrl("");
        })
        .finally(() => {
          setLoading(false);
        });
    }
  }, [slug, frontmatter]);

  // Map objectFit to Tailwind class
  const objectFitClass = {
    cover: "object-cover",
    contain: "object-contain",
    fill: "object-fill",
    none: "object-none",
    "scale-down": "object-scale-down"
  }[objectFit];

  return (
    <div
      className={`relative overflow-hidden ${className}`}
      style={{
        width: "100%",
        height: "100%",
      }}
    >
      {loading ? (
        <div className="w-full h-full flex items-center justify-center bg-gray-600">
          <Image
            src="/images/Site/Logo/logo_.png"
            alt="Loading..."
            width={60}
            height={60}
