import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import { Article } from '@/types/core';
import { BadgeData } from '@/types/core';

export async function loadBadgeData(slug: string): Promise<BadgeData | null> {
  try {
    // Try to load data from the frontmatter file
    const frontmatterPath = path.join(
      process.cwd(),
      'content',
      'components',
      'frontmatter',
      `${slug}.md`
    );

    if (fs.existsSync(frontmatterPath)) {
      const fileContent = fs.readFileSync(frontmatterPath, 'utf8');
      const { data } = matter(fileContent);

      if (data.chemicalProperties) {
        return {
          symbol: data.chemicalProperties.symbol,
          formula: data.chemicalProperties.formula,
          materialType: data.chemicalProperties.materialType,
          atomicNumber: data.chemicalProperties.atomicNumber
        };
      }
    }

    return null;
  } catch (error) {
    console.error(`Error loading badge data for ${slug}:`, error);
    return null;
  }
}

// app/utils/badgeUtils.ts
import { MaterialType, BadgeData } from '@/types/core';

/**
 * Maps material types to colors for badges
 */
export function getMaterialColor(materialType?: string): string {
  if (!materialType) return "blue";

  const typeMap: Record<string, string> = {
    metal: "blue",
    ceramic: "green",
    polymer: "purple",
    composite: "yellow",
    semiconductor: "red",
    compound: "gray",
    element: "teal",
    alloy: "indigo",
    other: "blue",
  };

  return typeMap[materialType.toLowerCase()] || "blue";
}

/**
 * Extracts badge data from an item (article, card, etc.) based on its metadata and slug
 * This centralizes badge logic so it can be used by both Card and Article components
 */
export function getBadgeData(item: { badge?: BadgeData; metadata?: Record<string, unknown>; frontmatter?: Record<string, unknown>; slug?: string; category?: string }, options: { showBadge?: boolean, forceBadge?: boolean } = {}): BadgeData | null {
  const { showBadge = true, forceBadge = false } = options;
  const metadata = item.metadata || {};
  const slug = item.slug || '';

  // If showBadge is false and we're not forcing, don't show a badge
  if (!showBadge && !forceBadge) return null;

  // If explicit badge data is provided, use it
  if (item.badge) return { ...item.badge, slug };

  // Extract from metadata if available
  if (metadata.chemicalProperties) {
    const props = metadata.chemicalProperties as Record<string, any>;

    // Only return badge data if we have at least a symbol or formula
    if (props.symbol || props.formula) {
      const badgeData: BadgeData = {
        symbol: props.symbol as string,
        formula: props.formula as string,
        atomicNumber: props.atomicNumber as number,
        materialType: (props.materialType || metadata.category || 'other') as MaterialType,
        color: getMaterialColor(props.materialType as string || metadata.category as string),
        slug
      };

      // Cache the badge data for this slug
      if (slug) {
        cacheBadgeData(slug, badgeData);
      }

      return badgeData;
    }
  }

  // Try to extract from metadata directly if chemicalProperties object isn't available
  if (metadata.symbol || metadata.formula) {
    const badgeData: BadgeData = {
      symbol: metadata.symbol as string | undefined,
      formula: metadata.formula as string | undefined,
      atomicNumber: metadata.atomicNumber as number | undefined,
      materialType: (metadata.materialType || metadata.category || 'other') as MaterialType,
      color: getMaterialColor(metadata.materialType as string || metadata.category as string),
      slug
    };

    // Cache the badge data for this slug
    if (slug) {
      cacheBadgeData(slug, badgeData);
    }

    return badgeData;
  }

  // Check frontmatter if available
  if (item.frontmatter) {
    const fm = item.frontmatter as Record<string, any>;

    if (fm.chemicalProperties) {
      const props = fm.chemicalProperties as Record<string, any>;

      if (props.symbol || props.formula) {
        const badgeData: BadgeData = {
          symbol: props.symbol as string,
          formula: props.formula as string,
          atomicNumber: props.atomicNumber as number,
          materialType: (props.materialType || fm.category || 'other') as MaterialType,
          color: getMaterialColor(props.materialType as string || fm.category as string),
          slug
        };

        // Cache the badge data for this slug
        if (slug) {
          cacheBadgeData(slug, badgeData);
        }

        return badgeData;
      }
    }

    // Direct chemical properties in frontmatter
    if (fm.symbol || fm.formula) {
      const badgeData: BadgeData = {
        symbol: fm.symbol as string | undefined,
        formula: fm.formula as string | undefined,
        atomicNumber: fm.atomicNumber as number | undefined,
        materialType: (fm.materialType || fm.category || 'other') as MaterialType,
        color: getMaterialColor(fm.materialType as string || fm.category as string),
        slug
      };

      // Cache the badge data for this slug
      if (slug) {
        cacheBadgeData(slug, badgeData);
      }

      return badgeData;
    }
  }

  // Check if we already have cached data for this slug
  if (slug) {
    const cachedBadge = getBadgeDataBySlug(slug);
    if (cachedBadge) {
      return cachedBadge;
    }
  }

  return null;
}

/**
 * Cache for storing badge data by slug
 * This allows us to associate badges with content across different views
 */
const badgeCache: Record<string, BadgeData> = {};

/**
 * Store badge data for a specific slug
 */
export function cacheBadgeData(slug: string, badgeData: BadgeData): void {
  if (!slug) return;
  badgeCache[slug] = badgeData;
}

/**
 * Get badge data for a specific slug
 */
export function getBadgeDataBySlug(slug: string): BadgeData | null {
  if (!slug) return null;
  return badgeCache[slug] || null;
}

// app/utils/contentUtils.ts
// Mark this file as server-only to prevent client-side imports of Node.js modules
'use server';

import fs from 'fs/promises';
import { existsSync } from 'fs';
import path from 'path';
import { logger, safeContentOperation } from './logger';
import { safeMatterParse } from './yamlSanitizer';
import { Article } from '@/types/core';

export type { Article };

export async function getAllArticleSlugs(): Promise<string[]> {
  return safeContentOperation(async () => {
    // Get slugs from any component directory (metatags, content, etc.)
    const metatagsDir = path.join(process.cwd(), 'content', 'components', 'metatags');
    const contentDir = path.join(process.cwd(), 'content', 'components', 'content');
    const frontmatterDir = path.join(process.cwd(), 'content', 'components', 'frontmatter');

    const slugs: string[] = [];

    // Check metatags directory first
    if (existsSync(metatagsDir)) {
      const metaFiles = await fs.readdir(metatagsDir);
      const metaSlugs = metaFiles
        .filter(file => file.endsWith('.md'))
        .map(file => file.replace('.md', ''));
      slugs.push(...metaSlugs);
    }

    // Then check content directory
    if (existsSync(contentDir)) {
      const contentFiles = await fs.readdir(contentDir);
      const contentSlugs = contentFiles
        .filter(file => file.endsWith('.md'))
        .map(file => file.replace('.md', ''));

      // Add only unique slugs
      contentSlugs.forEach(slug => {
        if (!slugs.includes(slug)) {
          slugs.push(slug);
        }
      });
    }

    // Finally check frontmatter directory
    if (existsSync(frontmatterDir)) {
      const frontmatterFiles = await fs.readdir(frontmatterDir);
      const frontmatterSlugs = frontmatterFiles
        .filter(file => file.endsWith('.md'))
        .map(file => file.replace('.md', ''));

      // Add only unique slugs
      frontmatterSlugs.forEach(slug => {
        if (!slugs.includes(slug)) {
          slugs.push(slug);
        }
      });
    }

    return slugs;
  }, [], 'getAllArticleSlugs');
}

export async function getAllArticles(): Promise<Article[]> {
  const slugs = await getAllArticleSlugs();
  const articles: Article[] = [];

  for (const slug of slugs) {
    // Try to find the article in any of the content directories
    const directories = [
      path.join(process.cwd(), 'content', 'components', 'frontmatter'),
      path.join(process.cwd(), 'content', 'components', 'metatags'),
      path.join(process.cwd(), 'content', 'components', 'content')
    ];

    let articleData: Article | null = null;

    for (const dir of directories) {
      const filePath = path.join(dir, `${slug}.md`);

      try {
        if (existsSync(filePath)) {
          const fileContents = await fs.readFile(filePath, 'utf8');
          const { data } = safeMatterParse(fileContents);

          articleData = {
            slug,
            title: data.title,
            name: data.name || '',
            headline: data.headline || '',
            description: data.description || '',
            image: data.image || '',
            imageAlt: data.imageAlt || '',
            tags: data.tags || [],
            website: data.website || '',
            author: data.author || {},
            metadata: {
              keywords: data.keywords || [],
              category: data.category || '',
              articleType: data.articleType || '',
              subject: data.subject || '',
              chemicalProperties: data.chemicalProperties || {},
              properties: data.properties || [],
              applications: data.applications || [],
              environmentalImpact: data.environmentalImpact || [],
              regulatoryStandards: data.regulatoryStandards || [],
              outcomes: data.outcomes || [],
              composition: data.composition || [],
              compatibility: data.compatibility || [],
              images: data.images || {}, // Add images to metadata
              technicalSpecifications: data.technicalSpecifications || {},
              countries: data.countries || [],
              manufacturingCenters: data.manufacturingCenters || []
            } as any
          } as Article;

          // For frontmatter files, always try to read any top-level properties
          if (dir.includes('frontmatter') && articleData) {
            // Add any missing properties from raw data to articleData
            Object.entries(data).forEach(([key, value]) => {
              // articleData is guaranteed to be non-null here because of the check in the if condition
              if (key !== 'metadata' && articleData && !(articleData as any)[key]) {
                (articleData as any)[key] = value;
              }
            });
          }

          break;
        }
      } catch (error) {
        logger.error(`Error loading article for ${slug} in ${dir}`, error, { slug, dir });
      }
    }

    if (articleData) {
      articles.push(articleData);
    }
  }

  return articles;
}

export async function getArticleBySlug(slug: string): Promise<Article | null> {
  // Try to find the article in any of the content directories
  const directories = [
